#!/usr/bin/env node
// ============================================================
// Bundle Script — Reads site-kit/ files and generates a JS
// bundle that getSiteKitFiles() can return directly.
// Run: node SelfBuildingWebsites/scripts/bundle.js
// Output: SelfBuildingWebsites/wizard/site-kit-bundle.js
// ============================================================

const fs = require('fs');
const path = require('path');

const SITE_KIT_DIR = path.resolve(__dirname, '..', 'site-kit');
const OUTPUT_FILE = path.resolve(__dirname, '..', 'wizard', 'site-kit-bundle.js');

// Files to bundle, in the order they'll be pushed to the user's repo.
// Paths are relative to site-kit/.
const FILES_TO_BUNDLE = [
  'package.json',
  'vercel.json',
  '.gitignore',
  '.env.example',
  'README.md',
  'css/style.css',
  'js/main.js',
  'index.html',
  'contact.html',
  'gallery.html',
  'menu.html',
  'testimonials.html',
  'faq.html',
  'admin.html',
  'api/agent.js',
  'api/enhance-prompt.js',
  'api/contact.js',
  'api/revert.js',
  'api/site-info.js',
];

function escapeForTemplateLiteral(str) {
  // Escape backticks, ${, and backslashes for use inside JS template literals
  return str
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$\{/g, '\\${');
}

function main() {
  const entries = [];
  let totalSize = 0;

  for (const relPath of FILES_TO_BUNDLE) {
    const fullPath = path.join(SITE_KIT_DIR, relPath);

    if (!fs.existsSync(fullPath)) {
      console.error(`WARNING: ${relPath} not found at ${fullPath}, skipping`);
      continue;
    }

    const content = fs.readFileSync(fullPath, 'utf-8');
    const escaped = escapeForTemplateLiteral(content);
    entries.push({ path: relPath, escaped });
    totalSize += content.length;
    console.log(`  + ${relPath} (${content.length} chars)`);
  }

  // Also pick up api/upload.js if it exists (Phase 4)
  const uploadPath = path.join(SITE_KIT_DIR, 'api', 'upload.js');
  if (fs.existsSync(uploadPath)) {
    const content = fs.readFileSync(uploadPath, 'utf-8');
    const escaped = escapeForTemplateLiteral(content);
    entries.push({ path: 'api/upload.js', escaped });
    totalSize += content.length;
    console.log(`  + api/upload.js (${content.length} chars)`);
  }

  // Generate the JS output
  const fileEntries = entries.map(e =>
    `  '${e.path}': \`${e.escaped}\``
  ).join(',\n\n');

  const output = `// AUTO-GENERATED by scripts/bundle.js — do not edit manually.
// Contains all site-kit files for the BuildMySite wizard.
// Regenerate with: node SelfBuildingWebsites/scripts/bundle.js

export const SITE_KIT_FILES = {
${fileEntries}
};
`;

  fs.mkdirSync(path.dirname(OUTPUT_FILE), { recursive: true });
  fs.writeFileSync(OUTPUT_FILE, output, 'utf-8');

  console.log(`\nBundle generated: ${OUTPUT_FILE}`);
  console.log(`  ${entries.length} files, ${totalSize} chars total`);
}

main();
